  function gradeName(g){ if(g==='g7')return '七年级'; if(g==='g8')return '八年级'; return g; }
  // 返回该科该年级的知识点 path 列表（七/八年级 + 全学段）。
  function pointsFor(subjectId, grade){
    var gn = gradeName(grade);
    return (POINTS[subjectId]||[]).filter(function(p){ return !gn || p.grade===gn || p.grade==='全学段'; }).map(function(p){ return p.path; });
  }
  window.Knowledge = { POINTS: POINTS, pointsFor: pointsFor };
